INSERT INTO "public"."Classes" (class_code, class_title, class_description, class_status) VALUES
   ('CS492', 'Computer Science Team Project II', 'This is the second course in a two course sequence that entails the end-to-end development of a software application in a project team setting. The course reinforces students abilities to choose and apply the right principles, engineering processes, methods, and tools to conduct productive software implementation and testing. As members of a project team, students will use the requirements, design specifications, and the prototype created in CS491 to implement and test the produced software application. Every project team will provide a live demo of the running application they have produced to other project teams, and students will be required to provide their feedback regarding the demos made by other project teams.', 'active')
  ,('CS491', 'Computer Science Team Project I', 'This is the first course in a two course sequence that entails the end-to-end development of a software application in a project team setting. Students in this class will work in project teams. Every student will join only one project team and will assume at least one type of job function typical in a software development project, such as requirement collection and analysis, system function specification, architecture design, component design, prototyping, implementation, testing, project management, etc. Each project team typically consists of students from the same concentration. However, students from the different concentrations may be allowed to work in the same project team. The course reinforces the principles of requirements collection/analysis and software design using engineering processes, methods and tools. As members of a project team, students will work to define the problem or opportunity, identify constraints, collect the requirements, complete a high level design, and prepare a product prototype. Students also deliver a professional report and presentation.', 'active')
  ,('CS469', 'Software Quality Assurance', 'Software Quality Assurance (SQA) is a set of systematic activities that software testers must perform in order to ensure the quality of a software project. This course provides an overview of the techniques, approaches, and processes used for SQA. The course covers various types of tests, such as unit testing, usability testing, stress testing, integration testing, and system testing. Students will have the opportunity to apply SQA theory as they perform software tests.', 'active')
  ,('CS379', 'Machine Learning', 'This course introduces students to the foundations, commonly used algorithms and techniques, as well as various types of applications of Machine Learning which is a branch of Artificial Intelligence. The course discusses the strengths and weaknesses of different machine learning methodologies such as decision trees, neural networks, clustering, Naive Bayes, and regression based on the application requirements. Students will complete several small software assignments to implement Machine Learning functionality in a given application.', 'active')
  ,('CS468', 'Software Service Construction', 'This course introduces students to how to apply the agile software development approach (process and techniques) to develop Software as a Service by using a proper type of cloud (private, public, or hybrid) enabled web application framework. Students will explore the principles and highly effective methods to design, implement and testing as well as deploying a software on a public cloud as a service.', 'active')
;